mapper.select:
select id, product_id, user_id, status, created_at, updated_at
from advisor_product_subscription
where user_id = #{userId}
  and product_id = #{productId}
limit 1

mapper.sql:
from advisor_product_subscription s
         inner join advisor_product p on p.id = s.product_id
         left join (
    select n1.product_id, n1.nav, n1.cum_return
    from advisor_product_nav n1
             inner join (
        select product_id, max(nav_date) as max_nav_date
        from advisor_product_nav
        group by product_id
    ) latest on latest.product_id = n1.product_id and latest.max_nav_date = n1.nav_date
) nav on nav.product_id = p.id
where s.user_id = #{userId}

    and p.name like concat('%', #{keyword}, '%')


    and s.status = #{subscriptionStatus}


    and p.status = #{productStatus}
